import { useState, useEffect } from 'react';

export const useConversation = () => {
  const [messages, setMessages] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({});
  const [currentStep, setCurrentStep] = useState({ type: 'text' });

  const systemInstructions = `
    You are a NIMHANS Clinical Data Engine. 
    GOAL: Collect history. Use "choice" type for Gender, Yes/No, or Symptom lists.
    RESPOND ONLY IN JSON:
    {
      "message": "string",
      "type": "text" | "choice",
      "field": "string",
      "options": ["Required if type is choice"]
    }
  `;

  // Internal helper to fix LLM mistakes
  const validateResponse = (jsonString) => {
    try {
      const parsed = JSON.parse(jsonString);
      // If LLM says choice but gave no options, force it to text to prevent crash
      if (parsed.type === 'choice' && (!parsed.options || !Array.isArray(parsed.options))) {
        parsed.type = 'text';
      }
      return parsed;
    } catch (e) {
      return { message: "Could you tell me more about that?", type: "text", field: "clarification" };
    }
  };

  useEffect(() => {
    const init = async () => {
      setIsTyping(true);
      const res = await callOllama("Start the session. Ask for the patient's name.");
      const validated = validateResponse(res);
      setMessages([{ sender: 'bot', text: validated.message }]);
      setCurrentStep(validated);
      setIsTyping(false);
    };
    init();
  }, []);

  const callOllama = async (prompt) => {
    try {
      const response = await fetch("http://localhost:11434/api/generate", {
        method: "POST",
        body: JSON.stringify({
          model: "mistral",
          prompt: `INSTRUCTIONS: ${systemInstructions}\n\nCONTEXT: ${prompt}`,
          stream: false,
          format: "json"
        }),
      });
      const data = await response.json();
      return data.response;
    } catch (error) {
      return JSON.stringify({ message: "Ollama connection error.", type: "text" });
    }
  };

  const handleUserAnswer = async (answer) => {
    setMessages(prev => [...prev, { sender: 'user', text: Array.isArray(answer) ? answer.join(", ") : answer }]);
    setIsTyping(true);

    const updatedData = { ...userData, [currentStep.field]: answer };
    setUserData(updatedData);

    const contextPrompt = `
      Data collected: ${JSON.stringify(updatedData)}
      Patient's last answer: "${answer}"
      Next NIMHANS step? (Prioritize "choice" with options to minimize typing).
    `;

    const nextJson = await callOllama(contextPrompt);
    const validated = validateResponse(nextJson);
    
    setMessages(prev => [...prev, { sender: 'bot', text: validated.message }]);
    setCurrentStep(validated);
    setIsTyping(false);
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
